var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐흠~ 오늘도 계좌에 주님의 은총이 가득하구나!","JPN":"ふふ～ん、今日も口座に主の恩寵がたくさん！","ENG":"Haha! Another day, another divine blessing deposited into my account!","TWN":"哼哼～今天帳戶裡也充滿了主的恩寵啊！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_QM","text":{"KOREA":"<color=#ffd34c>상황 보고 바람.</color>","JPN":"<color=#ffd34c>状況報告求む。</color>","ENG":"<color=#ffd34c>Report status.</color>","TWN":"<color=#ffd34c>請彙報情況。</color>"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"칫, 일 끝난 건 귀신같이 아네.","JPN":"ちっ、どうして仕事が終わったってわかったんだよ？","ENG":"Tch, of course she'd check in the second I finish.","TWN":"嘖，竟然馬上就知道任務完成了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"상황 보고라니, 너무 딱딱한 거 아냐?","JPN":"状況報告って、堅苦しすぎだろ。","ENG":"Report status? That's way too formal.","TWN":"還要彙報情況，未免太正式了吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>일정 완료했습니다. ^^</color>","JPN":"<color=#ffd34c>仕事終わりました(^―^)</color>","ENG":"<color=#ffd34c>Mission complete. :)</color>","TWN":"<color=#ffd34c>任務已完成。^^</color>"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"처치 곤란이었던 성수들도 전부 치웠고, 오늘은 좋은 호텔에서 자볼까?","JPN":"持て余してた聖水も全部処理したし、今日はいいホテルに泊まっちゃうか？","ENG":"All the leftover holy water is taken care of, so I should splurge on a nice hotel tonight.","TWN":"那些難纏的聖獸也都處理掉了，今天要不要去找個好飯店住一晚？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"바르샤바에서 유명한 호텔이 있다고 들었는데~","JPN":"ワルシャワに有名なホテルがあるって聞いたんだよね～","ENG":"I heard there's a famous one in Warszawa...","TWN":"聽說華沙有一家很有名的飯店～"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네네. 루시아 릿지 받았습니다.","JPN":"はいはい。ルシア・リッジです。","ENG":"Yes, Lucia Ridge speaking.","TWN":"好的，收到。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗. 잔뜩 심통이 난 표정이네, 우리 멍멍이?","JPN":"ふふっ。苦虫をつぶしたような顔してるわね、ワンちゃん。","ENG":"Haha. You look so grumpy, Puppy.","TWN":"噗。生什麼悶氣呢，我的狗狗？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그야…… 이제 좀 쉬나 했더니 바로 연락하셨으니까요.","JPN":"そりゃ……休もうかなってところに連絡してきたらね。","ENG":"Well, of course I do. I was just about to relax, and then you called.","TWN":"那是因為……我剛想休息一下，你就聯絡我了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"직장 상사가 퇴근 시간 이후까지 간섭하는데, 어떻게 좋아하겠어요?","JPN":"職場の上司が退勤後までちょっかい出してくるのに、喜ぶわけないでしょう？","ENG":"What kind of employee likes a boss who bothers her after hours?","TWN":"誰會喜歡下班後還要工作呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고, 저 좀 그만 훔쳐보라고 말씀드렸잖아요.","JPN":"それと、覗き見はやめてくださいって言いましたよね。","ENG":"Also, I've told you before to quit spying on me.","TWN":"還有，我不是說了不要再偷看我了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그거 범죄예요. 범죄. 알아요?","JPN":"それ犯罪ですよ、犯罪。わかってるんですか？","ENG":"That's illegal. You do know that, right?","TWN":"那是犯罪，是犯罪。知道嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"미안해. 그럴 생각은 없었어.","JPN":"ごめんね、そういうつもりはなかったの。","ENG":"Sorry, I didn't mean to.","TWN":"對不起，我不是故意的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 부하 직원이 일을 잘하고 있는지 확인해야 하는 건 상사의 의무인걸?","JPN":"でも上司には部下がちゃんと仕事をしてるのか確認する義務があるでしょう？","ENG":"But it's my duty to check in on my subordinates, isn't it?","TWN":"但是，確認下屬是否在好好工作是上司的義務吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제가 샤워하는 것까지 몰래 사진 찍어서 보관하시잖아요.","JPN":"私がシャワーを浴びてるところまでこっそり撮影してるじゃないですか。","ENG":"You literally take secret photos of me in the shower.","TWN":"你還偷偷拍我洗澡的照片保存起來。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 어떻게 상사의 의무예요? 범죄지.","JPN":"何が上司の義務ですか。犯罪です。","ENG":"How is that a duty? That's a crime.","TWN":"那怎麼能是上司的義務？那是犯罪。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"물가에 내놓은 아이를 지켜보는 심정이라고 생각해 줘.","JPN":"子どもを見守る親心だと思ってほしいわね。","ENG":"Think of it as watching over a reckless child near the water.","TWN":"就當我是在擔心在水邊玩耍的下屬吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하아, 됐어요. 무슨 일이에요?","JPN":"もういいです。何の用ですか？","ENG":"*Sigh* Fine. What do you want?","TWN":"哀，算了。有什麼事嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈은 내일 보낼게요.","JPN":"お金なら明日送りますよ。","ENG":"I'll send the money tomorrow.","TWN":"錢明天會匯給你。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"설마 생활비를 다 쓰신 건 아니죠?","JPN":"まさか、もう生活費全部使っちゃったわけじゃないですよね？","ENG":"Don't tell me you spent all of your living expenses again?","TWN":"不會是把生活費全花光了吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"생활비는 조금 아슬아슬하지만, 문제없는 수준이야.","JPN":"生活費はギリギリだけど、問題ないわ。","ENG":"It's a little tight, but I'm managing.","TWN":"生活費有點緊張，但還在可控範圍內。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"중요한 의뢰가 들어와서, 바로 출발해 줘야겠어.","JPN":"重要な依頼が入って、すぐに出発してもらいたいの。","ENG":"But I have an important job for you, and you need to leave right away.","TWN":"有重要的委託來了，必須馬上出發。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네? 지금요?","JPN":"えっ？　今からですか？","ENG":"What? Now?","TWN":"蛤？現在嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 하지만…… 지금은 날도 너무 늦었고…….","JPN":"で、でも……もう夜も遅いですし……","ENG":"B-but... it's so late...","TWN":"可，可是……現在天色已晚……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그리고 곧 있으면 만월이잖아요. 너무 위험해요.","JPN":"それにもうすぐ満月じゃないですか。危険すぎます。","ENG":"And it's almost the full moon. That's way too dangerous.","TWN":"而且馬上就是月圓了，太危險了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"아~ 그렇지…… 만월이었네.","JPN":"あ～そうか……満月だったわね。","ENG":"Oh, right... The full moon.","TWN":"啊～對了……是月圓啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리가 5년간 에그타르트를 팔아도 못 가질 돈이긴 하지만.","JPN":"私たちが5年間エッグタルトを売っても得られない額ではあるけれど。","ENG":"We could make more money in this one job than selling egg tarts for five years, but...","TWN":"雖然這是我們賣五年蛋撻也賺不到的錢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래도 만월은 위험하니까…… 아쉽지만 거절하는 수밖에.","JPN":"満月は危険だし……残念だけど断るしかないわね。","ENG":"But a full moon is too dangerous... so I have no choice but to decline.","TWN":"但是月圓確實很危險……只能拒絕囉。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당장 가겠습니다.","JPN":"今すぐ向かいます。","ENG":"I'm on my way.","TWN":"我現在就去。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"덤으로 멍멍이의 <color=#ffd34c>병</color>을 연구할 비용도 벌 수 있을 거고.","JPN":"それにワンちゃんの<color=#ffd34c>病気</color>の研究資金も稼げるんだけど。","ENG":"And with the extra cash, we can fund more research into your <color=#ffd34c>sickness</color>, Puppy.","TWN":"順便還能賺到我家狗狗<color=#ffd34c>生病</color>的研究費用。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당장 가겠다고요.","JPN":"今すぐ行きますって。","ENG":"I said I'm going.","TWN":"都說了，我現在就可以出發。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"후훗, 의욕이 넘치는 모습이 보기 좋네.","JPN":"ふふっ、やる気満々でいいわね。","ENG":"Haha, I love that enthusiasm.","TWN":"呵呵，充滿幹勁的樣子真棒。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"챔버로 갈 준비를 해. 멍멍이.","JPN":"チェンバーに行きなさい、ワンちゃん。","ENG":"Get ready to head to Chamber, Puppy.","TWN":"準備去強巴吧，狗狗。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"챔버라니…… 여기서 거기까지 드는 돈이 얼마인지 알기나 해요?","JPN":"チェンバーって……ここからあそこまで行くのにどれくらいお金がかかるか、わかってるんですか？","ENG":"Chamber...? Do you have any idea how much it costs to get there?","TWN":"強巴？你知道到那裡要花多少錢嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"한 달은 놀고먹어도 되는 돈이잖아요.","JPN":"1か月は遊んで暮らせる額ですよ。","ENG":"That's enough money to live off of for a month!","TWN":"那可是一個月的生活費啊。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"손해를 생각하고 거절하기엔 너무 많은 돈이었어.","JPN":"損を考えて断るにはあまりにも高額だったの。","ENG":"It's too much to turn down.","TWN":"這筆錢太多了，無法拒絕。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"수도원을 보수할 자금도 마련해야 하거든.","JPN":"修道院を修理する資金も必要だし。","ENG":"We also need funds to repair the monastery.","TWN":"還需要籌措修繕修道院的資金。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그게 아니면, 갈 곳 없는 널 받아주고 뒷바라지해 준 날 버리고 떠나고 싶은 거니?","JPN":"それとも、居場所のないあなたを受け入れて、お世話までしてあげた私を捨てて行ってしまいたいの？","ENG":"Unless, of course, you'd rather leave me behind after everything I've done for you.","TWN":"難道說，你是想拋棄收留你、照顧你的我，離開嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래…… 그렇다면 언제든 떠나도 돼.","JPN":"そう……それならいつでも行っちゃっていいわ。","ENG":"All right... I guess you could leave whenever you want.","TWN":"好吧……如果是這樣你隨時可以走。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"또, 또 시작하신다.","JPN":"まただよ、また始まった。","ENG":"Ugh, here we go again.","TWN":"又來，又開始了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알았어요. 가면 되잖아요.","JPN":"わかりました。行けばいいんでしょう？","ENG":"Fine, fine. I'm going.","TWN":"知道了，我會去的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"성수를 좀 더 만들어 둬야겠어요.","JPN":"聖水をもっと作っておかないといけませんね。","ENG":"I better make more holy water.","TWN":"得多做些淨水才行。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"바가지를 잔뜩 씌워서, 의뢰금을 잔뜩 부풀려야죠.","JPN":"ご利益をアピールして、依頼料をぼったくらないと。","ENG":"I'll have to hike up my prices to make up for this...","TWN":"狠狠地削他們一筆，把委託金大大地抬高。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};